code:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX prov: <http://www.w3.org/ns/prov#>
PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT 
    ?p 
    ?o 
    (COALESCE(?olbl, "-") AS ?o_label)
    (COALESCE(?raw_o_class, "-") AS ?o_class)
    ?c_p 
    ?c_o 
    (COALESCE(?c_o_lbl, "-") AS ?c_o_label)
    (COALESCE(?raw_c_o_class, "-") AS ?c_o_class)
WHERE {
    <{obj_uri}> ?p ?o .

    OPTIONAL { ?o rdfs:label ?olbl . }

    OPTIONAL { ?o rdf:type ?raw_o_class . }

    OPTIONAL {
        <{obj_uri}> rdf:type prov:Collection .
        BIND(TRUE AS ?isCollection)
    }

    OPTIONAL {
        FILTER(bound(?isCollection))

        <{obj_uri}> prov:hadMember ?member .
        ?member ?c_p ?c_o .

        OPTIONAL { ?c_o rdfs:label ?c_o_lbl . }

        OPTIONAL { ?c_o rdf:type ?raw_c_o_class . }
    }
}

example_usage:
PREFIX prov: <http://www.w3.org/ns/prov#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?p ?o ?pe ?po
        WHERE {
            # 1. Start with the properties of the target object
            <http://testwebsite/testProgram#Generative_Task-system_prompt_generator> ?p ?o .

            # 2. Check if the object is a prov:Collection
            # This pattern only binds ?isCollection if <http://testwebsite/testProgram#Generative_Task-system_prompt_generator> is a prov:Collection
            OPTIONAL {
                <http://testwebsite/testProgram#Generative_Task-system_prompt_generator> rdf:type prov:Collection .
                BIND(TRUE AS ?isCollection)
            }

            OPTIONAL {
                FILTER (bound(?isCollection))
                <http://testwebsite/testProgram#Generative_Task-system_prompt_generator> prov:hadMember ?member .
                ?member ?pe ?po .
            }
        }

